    "feat.multi_llm":            {en:"Multi-LLM (15+ first-class · 100+ via LiteLLM)", ja:"複数 LLM 対応 (15+ 標準対応 · LiteLLM 経由 100+)", "zh-CN":"多 LLM (15+ 一类 · LiteLLM 100+)", ko:"멀티 LLM (15+ 기본 · LiteLLM 100+)", es:"Multi-LLM (15+ primarios · LiteLLM 100+)", fr:"Multi-LLM (15+ natifs · LiteLLM 100+)", de:"Multi-LLM (15+ direkt · LiteLLM 100+)", "pt-BR":"Multi-LLM (15+ primários · LiteLLM 100+)"},
