    "arch.l1":     {en:"Layer 1 — Personal Memory (auto-extracted)", ja:"Layer 1 — 個人メモリ (自動抽出)", "zh-CN":"Layer 1 — 个人记忆(自动抽取)", ko:"Layer 1 — 개인 메모리 (자동 추출)", es:"Capa 1 — Memoria Personal (auto-extraída)", fr:"Couche 1 — Mémoire Personnelle (auto-extraite)", de:"Schicht 1 — Persönlicher Speicher (auto-extrahiert)", "pt-BR":"Camada 1 — Memória Pessoal (auto-extraída)"},
    "arch.l2":     {en:"Layer 2 — Sleep-time Consolidation · 3 promotion paths", ja:"Layer 2 — Sleep-time Consolidation · 3 経路昇格", "zh-CN":"Layer 2 — Sleep-time 整合 · 3 路晋升", ko:"Layer 2 — Sleep-time 통합 · 3 경로 승격", es:"Capa 2 — Consolidación Sleep-time · 3 vías de promoción", fr:"Couche 2 — Consolidation Sleep-time · 3 voies de promotion", de:"Schicht 2 — Sleep-time-Konsolidierung · 3 Beförderungspfade", "pt-BR":"Camada 2 — Consolidação Sleep-time · 3 caminhos de promoção"},
    "arch.l3":     {en:"Layer 3 — Shared Memory Blocks (living)", ja:"Layer 3 — 共有メモリブロック (living)", "zh-CN":"Layer 3 — 共享记忆块(实时)", ko:"Layer 3 — 공유 메모리 블록 (실시간)", es:"Capa 3 — Bloques de Memoria Compartida (vivos)", fr:"Couche 3 — Blocs de Mémoire Partagée (vivants)", de:"Schicht 3 — Geteilte Speicherblöcke (lebendig)", "pt-BR":"Camada 3 — Blocos de Memória Compartilhada (vivos)"},
