    "arch.l5":     {en:"Layer 5 — Graph layer (optional)", ja:"Layer 5 — Graph 層 (任意)", "zh-CN":"Layer 5 — Graph 层(可选)", ko:"Layer 5 — Graph 레이어 (선택)", es:"Capa 5 — Capa Graph (opcional)", fr:"Couche 5 — Couche Graph (optionnelle)", de:"Schicht 5 — Graph-Schicht (optional)", "pt-BR":"Camada 5 — Camada Graph (opcional)"},
    "arch.l6":     {en:"Layer 6 — Skills Registry (promotion-aware)", ja:"Layer 6 — スキルレジストリ (昇格対応)", "zh-CN":"Layer 6 — 技能注册表(支持晋升)", ko:"Layer 6 — 스킬 레지스트리 (승격 지원)", es:"Capa 6 — Registro de Habilidades (con promoción)", fr:"Couche 6 — Registre des Compétences (sensible à la promotion)", de:"Schicht 6 — Skills-Registry (beförderungsbewusst)", "pt-BR":"Camada 6 — Registro de Habilidades (com promoção)"},
    "arch.auth":   {en:"Auth · RBAC · Audit · SSO (OIDC / SAML)", ja:"認証 · RBAC · 監査 · SSO (OIDC / SAML)", "zh-CN":"认证 · RBAC · 审计 · SSO (OIDC / SAML)", ko:"인증 · RBAC · 감사 · SSO (OIDC / SAML)", es:"Auth · RBAC · Auditoría · SSO (OIDC / SAML)", fr:"Auth · RBAC · Audit · SSO (OIDC / SAML)", de:"Auth · RBAC · Audit · SSO (OIDC / SAML)", "pt-BR":"Auth · RBAC · Auditoria · SSO (OIDC / SAML)"},

    "flows.kicker":      {en:"Three workflow flows", ja:"3 つの業務フロー", "zh-CN":"3 个工作流", ko:"3 개 업무 플로", es:"3 flujos de trabajo", fr:"3 flux métier", de:"Drei Workflow-Flows", "pt-BR":"3 fluxos de trabalho"},
    "flows.h2":          {en:"Run a multi-agent pipeline in 30 seconds.", ja:"30 秒でマルチエージェントパイプラインを実行。", "zh-CN":"30 秒内运行多代理流水线。", ko:"30 초만에 멀티 에이전트 파이프라인 실행.", es:"Ejecuta un pipeline multi-agente en 30 segundos.", fr:"Exécutez un pipeline multi-agents en 30 secondes.", de:"Multi-Agent-Pipeline in 30 Sekunden ausführen.", "pt-BR":"Execute um pipeline multi-agente em 30 segundos."},
    "flows.sales.title": {en:"Sales Agent Flow", ja:"営業エージェントフロー", "zh-CN":"销售代理流程", ko:"영업 에이전트 플로", es:"Flujo Sales Agent", fr:"Flux Sales Agent", de:"Sales-Agent-Flow", "pt-BR":"Fluxo Sales Agent"},
    "flows.sales.body":  {en:"Customer IR + past minutes + RAG → hypotheses → FAQ → proposal outline.", ja:"顧客 IR + 過去議事録 + RAG → 仮説 → FAQ → 提案アウトライン。", "zh-CN":"客户 IR + 过往会议纪要 + RAG → 假设 → FAQ → 提案大纲。", ko:"고객 IR + 과거 의사록 + RAG → 가설 → FAQ → 제안 개요.", es:"IR del cliente + actas + RAG → hipótesis → FAQ → esquema de propuesta.", fr:"IR client + comptes-rendus + RAG → hypothèses → FAQ → plan de proposition.", de:"Kunden-IR + frühere Protokolle + RAG → Hypothesen → FAQ → Vorschlagsentwurf.", "pt-BR":"IR do cliente + atas + RAG → hipóteses → FAQ → esboço da proposta."},
    "flows.logic.title": {en:"Logic Checker Flow", ja:"論理チェッカーフロー", "zh-CN":"逻辑检查流程", ko:"로직 체커 플로", es:"Flujo Logic Checker", fr:"Flux Logic Checker", de:"Logic-Checker-Flow", "pt-BR":"Fluxo Logic Checker"},
    "flows.logic.body":  {en:"Three agents (structure / contradiction / reader) review long docs.", ja:"3 エージェント (構造 / 矛盾 / 読者) で長文を整合性レビュー。", "zh-CN":"3 个代理(结构/矛盾/读者)审阅长文档。", ko:"3 에이전트 (구조 / 모순 / 독자) 가 장문 문서 검토.", es:"Tres agentes (estructura / contradicción / lector) revisan docs largos.", fr:"Trois agents (structure / contradiction / lecteur) revoient les docs longs.", de:"Drei Agenten (Struktur / Widerspruch / Leser) prüfen lange Dokumente.", "pt-BR":"Três agentes (estrutura / contradição / leitor) revisam documentos longos."},
    "flows.rag.title":   {en:"RAG Optimization Flow", ja:"RAG 最適化フロー", "zh-CN":"RAG 优化流程", ko:"RAG 최적화 플로", es:"Flujo RAG Optimization", fr:"Flux RAG Optimization", de:"RAG-Optimierungs-Flow", "pt-BR":"Fluxo RAG Optimization"},
    "flows.rag.body":    {en:"Self-correcting RAG: query expansion → eval → hallucination check loop.", ja:"自己修復型 RAG: クエリ拡張 → 評価 → ハルシネーション検査ループ。", "zh-CN":"自我修正 RAG:查询扩展 → 评估 → 幻觉检查循环。", ko:"자가 수정형 RAG: 쿼리 확장 → 평가 → 환각 검사 루프.", es:"RAG autocorrectivo: expansión de consulta → eval → bucle de verificación de alucinación.", fr:"RAG auto-correctif : expansion de requête → éval → boucle de vérification d'hallucination.", de:"Selbstkorrigierendes RAG: Query-Erweiterung → Bewertung → Halluzinations-Check-Schleife.", "pt-BR":"RAG autocorretivo: expansão de consulta → avaliação → loop de verificação de alucinação."},

