    "skills.investment.tag":      {en:"Investment", ja:"投資", "zh-CN":"投资", ko:"투자", es:"Inversión", fr:"Investissement", de:"Investment", "pt-BR":"Investimento"},
    "skills.investment.body":     {en:"Equity research, due diligence, portfolio decisions with bull/bear analysis.", ja:"エクイティリサーチ、デューデリ、ポートフォリオ判断 (bull/bear 分析)。", "zh-CN":"股权研究、尽职调查、组合决策(多空分析)。", ko:"주식 리서치, 실사, 포트폴리오 결정 (bull/bear 분석).", es:"Investigación de equity, due diligence, decisiones de portafolio con análisis bull/bear.", fr:"Recherche actions, due diligence, décisions de portefeuille (analyse bull/bear).", de:"Equity-Research, Due Diligence, Portfolio-Entscheidungen mit Bull/Bear-Analyse.", "pt-BR":"Pesquisa de equity, due diligence, decisões de portfólio com análise bull/bear."},
